import React from 'react';
import { UserPlus, Package, CreditCard, Home } from 'lucide-react';

function ProcessSection() {
  const steps = [
    {
      icon: <UserPlus size={40} className="text-primary-accent mb-6" strokeWidth={1.5} />,
      number: "01",
      title: "ĐĂNG KÝ",
      description: "Gia nhập cộng đồng Shipus.net và nhận ngay địa chỉ kho chuyên nghiệp tại Mỹ."
    },
    {
      icon: <Package size={40} className="text-primary-accent mb-6" strokeWidth={1.5} />,
      number: "02",
      title: "GỬI KHO MỸ",
      description: "Gửi món hàng yêu thích của bạn đến địa chỉ kho uy tín của chúng tôi tại Houston, TX."
    },
    {
      icon: <CreditCard size={40} className="text-primary-accent mb-6" strokeWidth={1.5} />,
      number: "03",
      title: "THANH TOÁN",
      description: "Hệ thống thanh toán minh bạch, tiện lợi sau khi kiện hàng đã về tới kho Việt Nam."
    },
    {
      icon: <Home size={40} className="text-primary-accent mb-6" strokeWidth={1.5} />,
      number: "04",
      title: "NHẬN HÀNG",
      description: "Thảnh thơi tận hưởng niềm vui mua sắm, chúng tôi giao hàng tận tay trên toàn quốc."
    },
  ];

  return (
    <section className="py-28 px-6 bg-white overflow-hidden relative" id="guide">
      <div className="container mx-auto text-center relative z-10">
        <h2 className="text-4xl md:text-5xl font-serif font-extrabold text-primary-dark tracking-tight leading-tight">
            Quy trình vận chuyển chuyên nghiệp
        </h2>
        <p className="mt-6 text-lg text-gray-500 font-sans font-light max-w-2xl mx-auto leading-relaxed">
            Chỉ với 4 bước đơn giản, kiện hàng của bạn sẽ được vận chuyển từ Mỹ về tới cửa nhà bạn một cách an toàn và nhanh chóng.
        </p>

        <div className="mt-20 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12 relative">
          {/* Đường kẻ mảnh kết nối giữa các bước (chỉ hiển thị trên desktop) */}
          <div className="hidden lg:block absolute top-1/2 left-0 w-full h-[1px] bg-gray-200 -z-10 transform -translate-y-1/2"></div>

          {steps.map((step, index) => (
            <div key={index} className="flex flex-col items-center p-8 bg-white border border-gray-100 rounded-xl shadow-soft transition-all transform hover:-translate-y-2 hover:shadow-xl relative overflow-hidden group">
              {/* Số thứ tự mờ phía sau */}
              <span className="absolute -top-4 -right-2 text-7xl font-serif font-extrabold text-gray-50 group-hover:text-gray-100 transition-colors z-0 select-none">
                {step.number}
              </span>

              <div className="z-10 flex flex-col items-center">
                {step.icon}
                <h3 className="text-xl font-sans font-bold text-primary-dark tracking-widest mb-4">{step.title}</h3>
                <p className="text-gray-500 font-sans font-light text-sm leading-relaxed text-center px-2">{step.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default ProcessSection;
